import{_ as r,o as t,c as o,a2 as e}from"./chunks/framework.DnrXFDHb.js";const c=JSON.parse('{"title":"G03: 核心員工流動率審計 — 經營審計專家報告","description":"","frontmatter":{},"headers":[],"relativePath":"審計報告庫/經營審計/3163_波若威/20260502/G03_核心員工流動率審計.md","filePath":"審計報告庫/經營審計/3163_波若威/20260502/G03_核心員工流動率審計.md"}'),l={name:"審計報告庫/經營審計/3163_波若威/20260502/G03_核心員工流動率審計.md"};function i(n,a,s,h,d,_){return t(),o("div",null,[...a[0]||(a[0]=[e('<p>我已讀取 03_審計專家_任務執行與技術協議.md，我將以專業職人視角，榨取最高密度的經營洞見。</p><h1 id="g03-核心員工流動率審計-—-經營審計專家報告" tabindex="-1">G03: 核心員工流動率審計 — 經營審計專家報告 <a class="header-anchor" href="#g03-核心員工流動率審計-—-經營審計專家報告" aria-label="Permalink to &quot;G03: 核心員工流動率審計 — 經營審計專家報告&quot;">​</a></h1><h2 id="📋-審計題目" tabindex="-1">📋 審計題目 <a class="header-anchor" href="#📋-審計題目" aria-label="Permalink to &quot;📋 審計題目&quot;">​</a></h2><p>核心技術或研發團隊的流動率為何？公司如何留住優秀人才？是否有關鍵人才流向競爭對手的跡象？</p><h2 id="🎯-專家直斷" tabindex="-1">🎯 專家直斷 <a class="header-anchor" href="#🎯-專家直斷" aria-label="Permalink to &quot;🎯 專家直斷&quot;">​</a></h2><ul><li><strong>核心結論</strong>：無公開離職率數據，但營收波動+薪酬凍漲使留才難度增；菲律賓擴產將加劇人力管理複雜度。</li><li><strong>風險評級</strong>：中</li><li><strong>數據時效</strong>：截至2025年度</li></ul><h2 id="📊-診斷評級" tabindex="-1">📊 診斷評級 <a class="header-anchor" href="#📊-診斷評級" aria-label="Permalink to &quot;📊 診斷評級&quot;">​</a></h2><p><strong>B（持平）</strong>：人均營收154.4萬(2023)→107.8萬(2024,-30%)→123.7萬(2025)，回復力道不足。人均淨利看似增長(24.2→25.7→27.8萬)但全賴業外撐盤，2024年本業人均營運利益-2,862元實質虧損。非主管年薪101.8→97.8萬(-3.9%)，薪資競爭力弱化。無ESG報告致核心團隊離職率無法驗證。</p><h2 id="🔍-答詢詳解" tabindex="-1">🔍 答詢詳解 <a class="header-anchor" href="#🔍-答詢詳解" aria-label="Permalink to &quot;🔍 答詢詳解&quot;">​</a></h2><h3 id="人力效能困境" tabindex="-1">人力效能困境 <a class="header-anchor" href="#人力效能困境" aria-label="Permalink to &quot;人力效能困境&quot;">​</a></h3><ul><li><strong>核心重點</strong>：人均營收154.4萬(2023)→107.8萬(2024,-30%)→123.7萬(2025)。人均淨利24.2→25.7→27.8萬，業外平滑效果顯著。</li><li><strong>深度見解</strong>：2024年全年營業利益-515萬，本業人力資本回報為負。業外收益若消退，人力投資報酬率將直接轉負。</li></ul><h3 id="留才機制" tabindex="-1">留才機制 <a class="header-anchor" href="#留才機制" aria-label="Permalink to &quot;留才機制&quot;">​</a></h3><ul><li><strong>核心重點</strong>：年終/三節/分紅/員工認股權。薪酬2023年高於同業13-15%（平均115.4萬，中位83.6萬）。</li><li><strong>深度見解</strong>：非主管年薪101.8→97.8萬(-3.9%)，實質減薪；AI光通訊人才需求旺，同業搶人壓力升。研發主管穩定但在其下核心工程師流動率不明，關鍵製程知識斷層恐延誤新產品進度。</li></ul><h3 id="人才競爭" tabindex="-1">人才競爭 <a class="header-anchor" href="#人才競爭" aria-label="Permalink to &quot;人才競爭&quot;">​</a></h3><ul><li><strong>核心重點</strong>：無大規模挖角報導，104/1111持續徵才，無大量關鍵職位同時釋出異常。</li><li><strong>深度見解</strong>：聯亞/華星光AI光通訊佈局形成人才競爭，公司轉型CPO需更多稀缺光電人才。菲律賓擴產至2,000-3,000人帶來跨國人力管理新挑戰。</li></ul><h2 id="💡-專家評析" tabindex="-1">💡 專家評析 <a class="header-anchor" href="#💡-專家評析" aria-label="Permalink to &quot;💡 專家評析&quot;">​</a></h2><ol><li><strong>營業利益連兩季為負期間的薪酬壓力</strong>：2024年下半年波若威營業損失合計3,137萬，這段期間的員工獎金與分紅必然受壓縮。若2025年營運雖回升但獎金恢復緩慢，核心工程師可能被光通訊同業以更高薪酬挖角，尤其聯亞、上詮等公司在CPO領域正積極擴編研發團隊。</li><li><strong>菲律賓擴產的人力管理風險</strong>：從單一中國生產基地轉為中山+菲律賓雙基地，員工人數從~1,800擴充到2,000-3,000人，文化差異、勞動法規、管理幹部培養都是巨大挑戰。若菲律賓廠的良率爬坡不順，將直接影響高毛利的800G/1.6T產品出貨時程，反過來加大對中山廠的依賴，形成地緣風險的雙重暴露。</li><li><strong>CSR/ESG資訊透明度不足的治理疑慮</strong>：公司未在公開管道發布完整永續報告書，核心技術團隊離職率、女性主管佔比（2023年僅22.2%）、職業安全等KPI均無法取得。對重視ESG的國際客戶（如NVIDIA供應鏈要求）而言，資訊不透明可能成為供應商資格審查的扣分項。</li></ol><h2 id="📚-證據來源" tabindex="-1">📚 證據來源 <a class="header-anchor" href="#📚-證據來源" aria-label="Permalink to &quot;📚 證據來源&quot;">​</a></h2><ul><li><strong>web_search</strong>：波若威員工人數與薪資數據（Goodinfo, Goodjob.life, 1111人力銀行）</li><li><strong>web_search</strong>：波若威留才制度與福利措施（1111人力銀行、Browave官網）</li><li><strong>web_search</strong>：波若威菲律賓廠擴產計畫（LINE Today, 2025-2026報導）</li><li><strong>FinMind</strong>：TaiwanStockFinancialStatements (3163, 2023Q1-2025Q4) — 人均營收/人均淨利推算依據</li><li><strong>web_search</strong>：光通訊產業人才競爭態勢（104科技業人才報告 2026）</li><li><strong>數據限制</strong>：員工流動率、核心技術團隊離職率等數據因公司未發布ESG報告而無法取得，標註為「資料不足」</li></ul>',19)])])}const u=r(l,[["render",i]]);export{c as __pageData,u as default};
